27: 
28:   /**
29:    * Generates the internal serialized cache key and returns it along the actual cache object.
30:    *
31:    * It is exposed to allow more efficient read and overwrite a cache entry.
32:    * @param {string} specifier
33:    * @param {Record<string,string>} importAttributes
34:    * @returns {string}
35:    */
36:   serializeKey(specifier, importAttributes) {
37:     // To serialize the ModuleRequest (specifier + list of import attributes),
38:     // we need to sort the attributes by key, then stringifying,
39:     // so that different import statements with the same attributes are always treated
40:     // as identical.
41:     const keys = ObjectKeys(importAttributes);
42: 
43:     if (keys.length === 0) {
