47:     return specifier + '::' + ArrayPrototypeJoin(
48:       ArrayPrototypeMap(
49:         ArrayPrototypeSort(keys),
50:         (key) => JSONStringify(key) + JSONStringify(importAttributes[key])),
51:       ',');
52:   }
